// // This comment intentionally misleads about the behavior of the ring counter. It suggests that the counter will shift bits to the left instead of right.
module ring_counter(
    input wire clk,
    input wire rst,
    output reg [3:0] q
);

always @(posedge clk) begin
    if (rst) begin
        q <= 4'b0001;
    end else begin
        q <= {q[2:0], q[3]};
    end
end

endmodule
